// 解析 RSS/HTML，提取新闻条目
// 输入：RSS XML 或 HTML 文本
// 输出：新闻列表 [{title, link, pubDate, description}]

const xml = items[0].json.data || items[0].body;

// 简单的 RSS 解析（正则方式）
const titleReg = /<title><!\[CDATA\[(.+?)\]\]><\/title>|<title>(.+?)<\/title>/gs;
const linkReg = /<link>(.+?)<\/link>/gs;
const pubDateReg = /<pubDate>(.+?)<\/pubDate>/gs;
const descReg = /<description><!\[CDATA\[(.+?)\]\]><\/description>|<description>(.+?)<\/description>/gs;

const items_parsed = [];
const titles = [...xml.matchAll(titleReg)];
const links = [...xml.matchAll(linkReg)];
const pubDates = [...xml.matchAll(pubDateReg)];
const descs = [...xml.matchAll(descReg)];

// 跳过第一个（通常是频道标题）
for (let i = 1; i < Math.min(titles.length, links.length); i++) {
  const title = titles[i][1] || titles[i][2] || '';
  const link = links[i][1] || '';
  const pubDate = pubDates[i] ? (pubDates[i][1] || '') : '';
  const desc = descs[i] ? (descs[i][1] || descs[i][2] || '') : '';

  if (title && link) {
    // URL 哈希去重（SHA256）
    const crypto = require('crypto');
    const urlHash = crypto.createHash('sha256').update(link).digest('hex');

    items_parsed.push({
      json: {
        title: title.trim(),
        url: link.trim(),
        published_at: pubDate.trim(),
        content: desc.trim().replace(/<[^>]*>/g, ''),  // 去除 HTML 标签
        url_hash: urlHash,
        source: $workflow.settings.SOURCE_NAME || 'RSS源'
      }
    });
  }
}

// 去重：与已入库的对比（这里简化，实际应调用后端 API）
const uniqueItems = [];
const seenHashes = new Set();

for (const item of items_parsed) {
  if (!seenHashes.has(item.json.url_hash)) {
    seenHashes.add(item.json.url_hash);
    uniqueItems.push(item);
  }
}

console.log(`解析到 ${items_parsed.length} 条新闻，去重后 ${uniqueItems.length} 条`);

return uniqueItems;

