// Markdown 转 HTML（简易版）
// 输入：LLM 生成的 Markdown 文本
// 输出：HTML 格式文本

const markdown = items[0].json.data?.answer || '';

// 简易 Markdown 转 HTML
let html = markdown
  // 标题
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^# (.+)$/gm, '<h1>$1</h1>')
  // 粗体
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // 斜体
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  // 链接
  .replace(/\[(.+?)\]\((.+?)\)/g, '<a href="$2">$1</a>')
  // 列表项
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/^\* (.+)$/gm, '<li>$1</li>')
  .replace(/^\d+\. (.+)$/gm, '<li>$1</li>')
  // 换行
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>');

// 包裹列表项
html = html.replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>');

// 包裹段落
html = '<p>' + html + '</p>';

// 添加邮件样式
const styledHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 800px; margin: 0 auto; padding: 20px; }
    h1 { color: #0ea5e9; border-bottom: 2px solid #0ea5e9; padding-bottom: 10px; }
    h2 { color: #0369a1; margin-top: 20px; }
    h3 { color: #075985; }
    ul { background: #f5f5f5; padding: 15px; border-radius: 5px; }
    li { margin: 8px 0; }
    a { color: #0ea5e9; text-decoration: none; }
    a:hover { text-decoration: underline; }
    .footer { margin-top: 30px; padding-top: 20px; border-top: 1px solid #ddd; font-size: 12px; color: #666; text-align: center; }
  </style>
</head>
<body>
  <h1>🗞️ XU-News AI-RAG 日报</h1>
  <p><strong>生成时间：</strong>{{ new Date().toLocaleString('zh-CN') }}</p>
  <p><strong>新增新闻：</strong>{{ $('Aggregate-汇总结果').item.json.success_count }} 条</p>
  <hr>
  ${html}
  <div class="footer">
    <p>本邮件由 XU-News AI-RAG 系统自动生成</p>
    <p>访问系统：<a href="http://localhost:5173">http://localhost:5173</a></p>
  </div>
</body>
</html>
`;

return [{
  json: {
    html_content: styledHtml,
    plain_content: markdown,
    summary: items[0].json.data?.answer || '无摘要',
    news_count: $('Aggregate-汇总结果').item.json.success_count
  }
}];

// 错误日志记录
// 输入：错误信息
// 输出：格式化的日志对象

const error = $input.all()[0];
const errorNode = error.node || 'Unknown';
const errorMessage = error.error?.message || JSON.stringify(error);

const logData = {
  timestamp: new Date().toISOString(),
  workflow: $workflow.name,
  execution_id: $execution.id,
  error_node: errorNode,
  error_message: errorMessage,
  level: 'ERROR'
};

console.error('工作流执行失败:', logData);

return [{ json: logData }];
